def chunk_while(enum, acc, chunk_fun, after_fun)
    when is_function(chunk_fun, 2) and is_function(after_fun, 1) do
  lazy(
    enum,
    [acc | after_fun],
    fn f1 -> chunk_while_fun(chunk_fun, f1) end,
    &after_chunk_while/2
  )
end

